var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_F","text":{"KOREA":"하아, 하필 갑자기 비가 내리네. 일기예보엔 그런 얘기가 없었는데?","JPN":"はぁ、急に雨だなんて。天気予報では言ってなかったのに。","ENG":"*Sigh* It's raining all of a sudden. The weather forecast said nothing about this.","TWN":"哀，怎麼偏偏這個時候下雨，天氣預報都不準。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_M","text":{"KOREA":"하하… 그러게요. 괜히 견학 왔다가 폐잠수정에 꼼짝없이 갇혀버렸어요.","JPN":"はは……そうですね。見学に来ただけなのに、廃潜水艦の中に閉じ込められてしまいました。","ENG":"Hah hah... I know. This field trip wasn't a good idea after all. Now, we're stuck inside the abandoned submarine.","TWN":"哈哈…就是說，出來觀摩，結果被困在廢棄潛水艇裡。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_F","text":{"KOREA":"뭘 그렇게 빤히 쳐다보는 거야? 여기서 나갈 생각부터 해야지.","JPN":"何をそんなにじっと見てるの？　ここからどうやって出るかを考えないと。","ENG":"Why are you staring at me like that? Think about how to get out of here.","TWN":"你幹麼一直盯著我？先想想要怎麼離開吧！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_M","text":{"KOREA":"서두를 필요 없지 않아요? 출격까지도 아직 시간은 많이 남았고.","JPN":"急ぐ必要はないと思いますよ？　出撃までまだ時間はたっぷりありますし。","ENG":"But we're not in rush for anything. We've got plenty of time before our deployment.","TWN":"急什麼呢？距離出擊時間還很充裕。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_F","text":{"KOREA":"정신 차려. 난 부함장이고, 넌 견습 오퍼레이터야.","JPN":"何を言っているの。私は副艦長で、あなたは見習いオペレーターよ。","ENG":"Get a grip. I'm a deputy commander, and you're my training operator.","TWN":"你放尊重點！我可是副艦長，而你只是個實習領航員！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_M","text":{"KOREA":"상관없지 않아요?","JPN":"関係ないでしょう？","ENG":"Does that really matter?","TWN":"那又如何？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_F","text":{"KOREA":"뭐, 뭐라고?","JPN":"な、なにを言ってるの！？","ENG":"W-what?","TWN":"你…你說什麼？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_M","text":{"KOREA":"<color=#ffd34c>함선 밖에서는 계급장 떼고 싸워도 상관없다</color>. 부함장님께서 가르쳐 주신 거잖아요?","JPN":"<color=#ffd34c>艦船の外では階級章は関係ない</color>。副艦長が教えてくれたじゃないですか？","ENG":"\\"<color=#ffd34c>Ranks don't matter outside the ship.</color>\\" That's what you taught me, isn't it?","TWN":"這不是副艦長你教我的嗎？<color=#ffd34c>官階只有在艦船內管用</color>。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"ACTOR_NPC_DRAMA_F","face":"UNIT_IDLE"},"C":{"char_id":"ACTOR_NPC_DRAMA_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_F","text":{"KOREA":"너, 지금 나한테 말대꾸하는 거니?","JPN":"あなた、今上司に口答えしているの？","ENG":"Is that why you're talking the way you are right now?","TWN":"你現在是拿我的話來堵我嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_M","text":{"KOREA":"왜요? 제가 싫으세요?","JPN":"なぜですか？　俺のこと、嫌いですか？","ENG":"Why? Don't you like me?","TWN":"幹嘛這樣？你討厭我嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_F","text":{"KOREA":"그, 그건…!","JPN":"そ、それは……！","ENG":"I-I...","TWN":"我…！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"우, 우와아아…","JPN":"う、うわあああ……","ENG":"W-whoaaah!","TWN":"哇哇哇…"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"니콜 양~ 어젯밤에 유혹의 함교 챙겨 봤어?","JPN":"ニコルちゃ～ん、昨日の誘惑の艦橋、観た！？","ENG":"Nicole, did you watch The Bridge of Seduction episode last night?","TWN":"妮可～你昨天有追誘惑的艦橋嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗, 지금 재방송으로 보고 있었어요.","JPN":"あっ、今再放送を観ていました。","ENG":"Ah, I'm watching a rerun right now.","TWN":"沒有，我正在看重播～"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아아, 그 장면이네. 완전 화끈한 씬인데. 보면서 한 잔 하지 않고는 못 버티겠더라구.","JPN":"ああ、あの場面ね。すごく熱いシーンだったわよね。\\n観ながら一杯飲まずにはいられなかったわ。","ENG":"Ah, it's that scene! So hot, isn't it? It made me want a drink; I felt so thirsty all of a sudden.","TWN":"喔喔！剛好是最精彩的地方！看到這邊就覺得不來一杯不行！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"맞아요. 처음엔 무슨 이런 불경한 막장 이야기가 다 있나 싶었는데, 두근두근해서 눈을 뗄 수가 없더라고요.","JPN":"そうです。最初はなんて不敬な話と思ったのですが、\\n今は毎回ドキドキして目が離せません。","ENG":"Yes. At first, I couldn't believe how ridiculous this story was, but now I can't keep my eyes off the screen.","TWN":"真的，一開始我還想說這是什麼不正經的狗血劇，結果太好看，眼睛根本離不開電視。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};